#include <stdio.h>
#include <stdlib.h>

int *leftChild, *rightChild, *indeg;

void postOrder(int node) {
    if (node == 0) return;
    postOrder(leftChild[node]);
    postOrder(rightChild[node]);
    printf("%d ", node);
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        leftChild = (int*)calloc(N + 1, sizeof(int));
        rightChild = (int*)calloc(N + 1, sizeof(int));
        indeg = (int*)calloc(N + 1, sizeof(int));
        for (int i = 0; i < N - 1; ++i) {
            int p, c; char dir; scanf("%d %d %c", &p, &c, &dir);
            if (dir == 'L') leftChild[p] = c; else rightChild[p] = c;
            indeg[c]++;
        }
        int root = 1;
        for (int i = 1; i <= N; ++i) if (indeg[i] == 0) { root = i; break; }
        postOrder(root);
        printf("\n");
        free(leftChild); free(rightChild); free(indeg);
    }
    return 0;
}

