let idx = 0;
if (data.length === 0) process.exit(0);
const T = parseInt(data[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = parseInt(data[idx++]);
  const left = new Array(N + 1).fill(0);
  const right = new Array(N + 1).fill(0);
  const indeg = new Array(N + 1).fill(0);
  for (let i = 0; i < N - 1; i++) {
    const p = parseInt(data[idx++]);
    const c = parseInt(data[idx++]);
    const dir = data[idx++];
    if (dir === 'L') left[p] = c; else right[p] = c;
    indeg[c]++;
  }
  let root = 1;
  for (let i = 1; i <= N; i++) if (indeg[i] === 0) { root = i; break; }
  const result = [];
